def build_rag_prompt(question: str, chunks: list[str]) -> str:
    context = "\n\n".join(f"[{i + 1}] {chunk}" for i, chunk in enumerate(chunks))
    return (
        "Answer the question using ONLY the context below. "
        "If the answer is not in the context, say \"I don't know\" — do not guess.\n\n"
        f"Context:\n{context}\n\n"
        f"Question: {question}\n"
        "Answer:"
    )

import Anthropic from "@anthropic-ai/sdk";

async function streamChatResponse(prompt: string, onChunk: (text: string) => void): Promise<string> {
  const client = new Anthropic();
  const response = await client.messages.create({
    model: "claude-sonnet-4-5",
    max_tokens: 1024,
    messages: [{ role: "user", content: prompt }],
  });
  const text = response.content[0].type === "text" ? response.content[0].text : "";
  onChunk(text);
  return text;
}
